        unverified_header = jwt.get_unverified_header(id_token_raw)
        kid = unverified_header.get('kid')

        # Find the matching key in JWKS
        signing_key = None
        for key_data in jwks.get('keys', []):
            if key_data.get('kid') == kid:
                signing_key = jwt.algorithms.RSAAlgorithm.from_jwk(key_data)
                break

        if signing_key is None:
            app.logger.error("No matching signing key found in JWKS for kid: %s", kid)
            return None

        # SECURITY: Verify the token with full validation
        # - Verify signature with the IdP's public key
